import React, { useCallback, useEffect, useRef, useState } from 'react';
import axios from 'axios';
import he from '../i18n/he.json';

const FILTERS = [
  { key: 'today', label: 'היום' },
  { key: 'week', label: 'השבוע' },
  { key: 'month', label: 'החודש' },
  { key: 'all', label: 'הכל' },
];

function isToday(dateStr) {
  const d = new Date(dateStr);
  const now = new Date();
  return d.toDateString() === now.toDateString();
}

function isThisWeek(dateStr) {
  const d = new Date(dateStr);
  const now = new Date();
  const startOfWeek = new Date(now);
  startOfWeek.setDate(now.getDate() - now.getDay());
  startOfWeek.setHours(0, 0, 0, 0);
  return d >= startOfWeek;
}

function isThisMonth(dateStr) {
  const d = new Date(dateStr);
  const now = new Date();
  return d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear();
}

function playDing() {
  try {
    const ctx = new (window.AudioContext || window.webkitAudioContext)();
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.connect(gain);
    gain.connect(ctx.destination);
    osc.type = 'sine';
    osc.frequency.setValueAtTime(880, ctx.currentTime);
    osc.frequency.setValueAtTime(1100, ctx.currentTime + 0.15);
    gain.gain.setValueAtTime(0.5, ctx.currentTime);
    gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 1.2);
    osc.start(ctx.currentTime);
    osc.stop(ctx.currentTime + 1.2);
  } catch (_) {}
}

export default function AdminDashboard() {
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState('today');
  const prevCountRef = useRef(null);

  const fetchOrders = useCallback(async () => {
    try {
      const res = await axios.get('https://pizza-story-backend-u6n0.onrender.com/api/orders');
      const incoming = res.data;

      if (prevCountRef.current !== null && incoming.length > prevCountRef.current) {
        playDing();
      }
      prevCountRef.current = incoming.length;
      setOrders(incoming);
    } catch (_) {}
    setLoading(false);
  }, []);

  useEffect(() => {
    fetchOrders();
    const interval = setInterval(fetchOrders, 15000);
    return () => clearInterval(interval);
  }, [fetchOrders]);

  const handleDone = async (id) => {
    await axios.delete(`https://pizza-story-backend-u6n0.onrender.com/api/orders/${id}`);
    fetchOrders();
  };

  // Build per-phone history from all orders
  const customerHistory = {};
  orders.forEach((order) => {
    const p = order.phone;
    if (!customerHistory[p]) customerHistory[p] = { count: 0, total: 0 };
    customerHistory[p].count += 1;
    customerHistory[p].total += order.total || 0;
  });

  const filteredOrders = orders.filter((order) => {
    if (!order.createdAt) return filter === 'all';
    if (filter === 'today') return isToday(order.createdAt);
    if (filter === 'week') return isThisWeek(order.createdAt);
    if (filter === 'month') return isThisMonth(order.createdAt);
    return true;
  });

  return (
    <div className="max-w-6xl mx-auto mt-6 p-4">
      <h2 className="text-2xl font-bold text-tomato mb-4">{he.admin_dashboard}</h2>

      {/* Filter Tabs */}
      <div className="flex gap-2 mb-5">
        {FILTERS.map((f) => (
          <button
            key={f.key}
            onClick={() => setFilter(f.key)}
            className={`px-4 py-2 rounded-full font-bold text-sm transition ${
              filter === f.key
                ? 'bg-tomato text-white shadow'
                : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
            }`}
          >
            {f.label}
          </button>
        ))}
      </div>

      {loading ? (
        <div className="text-gray-500">טוען הזמנות...</div>
      ) : filteredOrders.length === 0 ? (
        <div className="text-gray-400 text-center py-12">{he.no_orders}</div>
      ) : (
        <div className="overflow-x-auto rounded-xl shadow">
          <table className="w-full bg-white text-sm" dir="rtl">
            <thead className="bg-tomato text-white">
              <tr>
                <th className="px-4 py-3 text-right font-semibold">טלפון</th>
                <th className="px-4 py-3 text-right font-semibold">שם לקוח</th>
                <th className="px-4 py-3 text-right font-semibold">כתובת</th>
                <th className="px-4 py-3 text-right font-semibold">תוספות</th>
                <th className="px-4 py-3 text-right font-semibold">תשלום</th>
                <th className="px-4 py-3 text-right font-semibold">סה"כ</th>
                <th className="px-4 py-3 text-right font-semibold">שעה</th>
                <th className="px-4 py-3 text-right font-semibold">פעולה</th>
              </tr>
            </thead>
            <tbody>
              {filteredOrders.map((order) => {
                const hist = customerHistory[order.phone] || { count: 0, total: 0 };
                const timeStr = order.createdAt
                  ? new Date(order.createdAt).toLocaleTimeString('he-IL', {
                      hour: '2-digit',
                      minute: '2-digit',
                    })
                  : '—';
                const payLabel =
                  order.paymentMethod === 'credit' ? he.credit : order.paymentMethod === 'cash' ? he.cash : '—';

                return (
                  <tr key={order.id} className="border-b border-gray-100 hover:bg-orange-50 transition">
                    {/* Phone — prominent */}
                    <td className="px-4 py-3 font-bold text-tomato text-base whitespace-nowrap">
                      {order.phone}
                    </td>
                    {/* Customer Name + history subtitle */}
                    <td className="px-4 py-3">
                      <div className="font-semibold">{order.name}</div>
                      <div className="text-xs text-gray-400 mt-0.5">
                        הזמנות קודמות: {hist.count} | סה"כ שולם: {hist.total}₪
                      </div>
                    </td>
                    <td className="px-4 py-3 text-gray-700">{order.address || '—'}</td>
                    <td className="px-4 py-3 text-gray-600 max-w-xs">
                      {order.toppings && order.toppings.length > 0
                        ? order.toppings.join(', ')
                        : '—'}
                    </td>
                    <td className="px-4 py-3 text-gray-600">{payLabel}</td>
                    <td className="px-4 py-3 font-bold text-gray-800 whitespace-nowrap">
                      {order.total}₪
                    </td>
                    <td className="px-4 py-3 text-gray-400 whitespace-nowrap">{timeStr}</td>
                    <td className="px-4 py-3">
                      <button
                        onClick={() => handleDone(order.id)}
                        className="bg-green-500 text-white px-3 py-1.5 rounded-lg text-xs font-bold hover:bg-green-600 transition whitespace-nowrap"
                      >
                        {he.mark_done}
                      </button>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}
